import{_ as e,o as t,c as i,a0 as a}from"./chunks/framework.B3sz4m_N.js";const n=""+new URL("../report/agentic-techniques-04-high-impact-gaps.png",import.meta.url).href,u=JSON.parse('{"title":"High-Impact Gaps","description":"Detailed analysis of the six most significant gaps between the Dark Factory workflow and agentic engineering best practices.","frontmatter":{"title":"High-Impact Gaps","description":"Detailed analysis of the six most significant gaps between the Dark Factory workflow and agentic engineering best practices."},"headers":[],"relativePath":"reports/agentic-engineering-techniques/04-high-impact-gaps.md","filePath":"reports/agentic-engineering-techniques/04-high-impact-gaps.md"}'),o={name:"reports/agentic-engineering-techniques/04-high-impact-gaps.md"};function r(l,s,p,h,c,d){return t(),i("div",null,[...s[0]||(s[0]=[a('<figure class="report-section-image-wrapper" aria-labelledby="fig-gaps-caption"><img src="'+n+`" alt="A suspension bridge with several missing planks, showing the clear path where repairs are needed" loading="lazy" class="report-section-image"><figcaption id="fig-gaps-caption">Identifying the structural gaps that limit workflow effectiveness</figcaption></figure><h2 id="_4-high-impact-gaps" tabindex="-1">4. High-Impact Gaps <a class="header-anchor" href="#_4-high-impact-gaps" aria-label="Permalink to &quot;4. High-Impact Gaps&quot;">​</a></h2><p>Six gaps have the highest impact on workflow quality and efficiency. Each is analysed with the book&#39;s rationale, the current state, and a concrete recommendation.</p><h3 id="gap-a-no-parallel-execution-in-the-orchestration-chain" tabindex="-1">Gap A: No parallel execution in the orchestration chain <a class="header-anchor" href="#gap-a-no-parallel-execution-in-the-orchestration-chain" aria-label="Permalink to &quot;Gap A: No parallel execution in the orchestration chain&quot;">​</a></h3><p><strong>The book&#39;s position:</strong> The Orchestrator Pattern&#39;s &quot;critical insight&quot; is that parallelism is achieved at the message level. All independent agents must be invoked in a single message for true concurrency. Sequential messages serialise execution.</p><blockquote><p>&quot;10 agents in parallel complete in roughly the same wall-clock time as 1 agent; 10 agents serialised take 10× longer.&quot;</p></blockquote><p><strong>Current state:</strong> The workflow runs all eight agents sequentially: architect → dev-lead → devops → governance → critic → cost-governor → strategist → reconciliation.</p><p><strong>Analysis:</strong> The first four agents are independent — they all read the same initiative intake and produce independent analysis. They don&#39;t need each other&#39;s output. The critic and cost-governor depend on prior output, so they must wait.</p><p><strong>Recommended structure:</strong></p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>Phase 1 (parallel):  architect + dev-lead + devops + governance</span></span>
<span class="line"><span>Phase 2 (parallel):  critic + cost-governor</span></span>
<span class="line"><span>Phase 3 (sequential): strategist</span></span>
<span class="line"><span>Phase 4 (sequential): reconciliation</span></span></code></pre></div><p>In Cursor, Phase 1 means spawning four Task calls in a single message. This would cut wall-clock time roughly in half with zero quality risk — agents produce identical output regardless of execution order.</p><p><strong>Effort:</strong> Low (update orchestration docs) <strong>Impact:</strong> High (50% time reduction)</p><hr><h3 id="gap-b-no-context-isolation-or-orchestrator-hygiene" tabindex="-1">Gap B: No context isolation or orchestrator hygiene <a class="header-anchor" href="#gap-b-no-context-isolation-or-orchestrator-hygiene" aria-label="Permalink to &quot;Gap B: No context isolation or orchestrator hygiene&quot;">​</a></h3><p><strong>The book&#39;s position:</strong> In multi-agent systems, each subagent should maintain its own context window. The orchestrator receives summaries and conclusions, not raw data. &quot;Context fill equals capability drain.&quot;</p><p><strong>Current state:</strong> When running the one-shot workflow, all agent outputs accumulate in a single context window. By the time the reconciliation agent runs, the context contains the full output of seven prior agents — potentially 10,000+ tokens of accumulated analysis.</p><p><strong>Why this matters:</strong> The reconciliation agent does the most complex work (synthesising, resolving conflicts, choosing trade-offs) but operates in the worst context conditions. The book&#39;s research shows token usage explains 80% of performance variance.</p><p><strong>Recommendation:</strong> Run each agent as a Cursor subagent (via the Task tool) with its own context window. Each subagent returns a structured summary — not the full analysis. The reconciliation agent then works with clean, compressed inputs from all prior agents.</p><p>Example subagent return format:</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## Architect Summary</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Architecture: Option A (CI + Bionic + Cursor)</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Key trade-off: OSS flexibility vs SaaS convenience</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Risk: Vendor deprecation for Bionic</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Complexity: Medium</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> Integration points: GitHub Actions, WordPress hooks, Laravel queues</span></span></code></pre></div><p><strong>Effort:</strong> Medium (restructure one-shot runner to use Task tool) <strong>Impact:</strong> High (improved reconciliation quality)</p><hr><h3 id="gap-c-no-few-shot-examples-in-skills" tabindex="-1">Gap C: No few-shot examples in skills <a class="header-anchor" href="#gap-c-no-few-shot-examples-in-skills" aria-label="Permalink to &quot;Gap C: No few-shot examples in skills&quot;">​</a></h3><p><strong>The book&#39;s position:</strong> &quot;When possible, show don&#39;t tell. Few-shot examples establish expected input/output format, tone and style, and edge case handling.&quot;</p><p><strong>Current state:</strong> No skill includes examples. The architect skill says &quot;produce a Text Diagram&quot; but never shows what one looks like. The critic says &quot;describe one realistic failure scenario&quot; but doesn&#39;t demonstrate expected depth.</p><p><strong>Why this matters:</strong> Without examples, the model infers output format from the structural description alone. This produces inconsistent results across runs — sometimes a text diagram is ASCII art, sometimes it&#39;s a Mermaid block, sometimes it&#39;s prose. The book warns that examples anchor format without constraining content creativity.</p><p><strong>Recommendation:</strong> Add a <code>## Example Output</code> section to each skill with one truncated input/output pair showing structure and tone. Prioritise architect (text diagram format), critic (depth of failure scenario), and reconciliation (conflict resolution format).</p><p>Example for the architect skill:</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## Example Output (truncated)</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">### 1. Problem Definition</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">WordPress sites require automated accessibility audits on content save.</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">### 2. Proposed Architecture</span></span></code></pre></div><p>WordPress (post_save hook) → Laravel queue job (accessibility-check) → axe-core headless scan → results stored in wp_postmeta → admin notice on next load</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span></span></span>
<span class="line"><span>### 3. Tooling Stack</span></span>
<span class="line"><span>- axe-core 4.x (OSS, headless via Puppeteer)</span></span>
<span class="line"><span>- Laravel Horizon for queue monitoring</span></span>
<span class="line"><span>- WordPress REST API for result retrieval</span></span></code></pre></div><p><strong>Effort:</strong> Medium (2 hours across top 3 skills) <strong>Impact:</strong> High (output consistency)</p><hr><h3 id="gap-d-no-uncertainty-handling" tabindex="-1">Gap D: No uncertainty handling <a class="header-anchor" href="#gap-d-no-uncertainty-handling" aria-label="Permalink to &quot;Gap D: No uncertainty handling&quot;">​</a></h3><p><strong>The book&#39;s position:</strong> &quot;Agents need guidance on when to act vs when to ask.&quot; Without explicit uncertainty handling, agents make arbitrary decisions on ambiguous inputs — sometimes guessing, sometimes asking, with no consistency.</p><p><strong>Current state:</strong> Only the reconciliation skill addresses missing information: &quot;If an input is missing, proceed with explicit assumptions and call out what&#39;s missing.&quot; No other skill has this guidance.</p><p><strong>Why this matters:</strong> When an initiative intake is ambiguous (unclear budget, vague success criteria, missing technical constraints), each skill handles the ambiguity differently. The architect might assume a constraint; the dev-lead might ignore it; the critic might flag it. This inconsistency compounds in reconciliation.</p><p><strong>Recommendation:</strong> Add a standardised <code>## Handling Uncertainty</code> section to every skill:</p><div class="language-markdown vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">markdown</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-light-font-weight:bold;--shiki-dark:#79B8FF;--shiki-dark-font-weight:bold;">## Handling Uncertainty</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">ASK the user when:</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> The initiative description is ambiguous and multiple interpretations are valid</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> A critical input (e.g., budget, compliance requirement) is missing</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> The change has significant consequences that depend on unstated assumptions</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">PROCEED with best judgment when:</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> The choice is between equivalent options (e.g., two similar tools)</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> The assumption can be explicitly stated and verified later</span></span>
<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> The information gap does not change the core recommendation</span></span></code></pre></div><p><strong>Effort:</strong> Low (1 hour across all skills) <strong>Impact:</strong> High (consistent handling of ambiguous inputs)</p><hr><h3 id="gap-e-no-evaluation-practice" tabindex="-1">Gap E: No evaluation practice <a class="header-anchor" href="#gap-e-no-evaluation-practice" aria-label="Permalink to &quot;Gap E: No evaluation practice&quot;">​</a></h3><p><strong>The book&#39;s position:</strong> &quot;Without measurement, development becomes guesswork. Evaluation separates engineering from tinkering.&quot; The book lays out a concrete workflow: write eval cases before modifying prompts, start with 3–5 cases, build eval sets from production failures.</p><p><strong>Current state:</strong> The 15-criteria evaluation rubric exists as infrastructure but has never been applied to skill outputs. No eval cases exist. No systematic measurement of skill quality occurs. The workflow operates at the &quot;vibes&quot; level of the book&#39;s evaluation spectrum.</p><p><strong>Why this matters:</strong> Without eval cases, there&#39;s no way to know whether a skill modification improved or degraded output. Changes to skills are based on intuition, and regressions go undetected until someone notices poor reconciliation output.</p><p><strong>Recommendation:</strong> Start minimal. For each of the three most critical skills (architect, critic, reconciliation), create one &quot;golden example&quot;:</p><ol><li>A known-good initiative intake (input)</li><li>What good output looks like for that input (expected output)</li><li>3–5 constraint checks (must-have elements)</li></ol><p>Store these in <code>research/eval-cases/</code>. When modifying a skill, run it against the golden example and compare. This is the book&#39;s &quot;Scripted&quot; evaluation tier — simple enough to maintain, rigorous enough to catch regressions.</p><p><strong>Effort:</strong> Medium (6 hours to create initial eval cases) <strong>Impact:</strong> High (transforms ad-hoc improvement into systematic engineering)</p><hr><h3 id="gap-f-specs-as-source-code-—-not-fully-realised" tabindex="-1">Gap F: Specs as source code — not fully realised <a class="header-anchor" href="#gap-f-specs-as-source-code-—-not-fully-realised" aria-label="Permalink to &quot;Gap F: Specs as source code — not fully realised&quot;">​</a></h3><p><strong>The book&#39;s position:</strong> &quot;Throwing away prompts after generating code is like checking in compiled binaries while discarding source.&quot; Initiative documents, research outputs, and plans should be treated as version-controlled first-class artifacts — the &quot;source code&quot; that agents execute.</p><p><strong>Current state:</strong> Initiative docs in <code>research/initiatives/</code> are partially this pattern. However:</p><ul><li>They&#39;re not structured as executable specs that agents can directly consume without manual copy-paste</li><li>The one-shot runner uses a placeholder (<code>[PASTE RESEARCH PROMPT HERE]</code>) rather than referencing a spec file path</li><li>There&#39;s no standardised spec format with frontmatter metadata</li></ul><p><strong>Recommendation:</strong> Standardise initiative intake as a structured spec file (with YAML frontmatter for metadata like title, budget, constraints, and target outcomes) that all agents can reference by file path. The one-shot runner should accept a spec file path, not require paste-in.</p><div class="language-yaml vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">yaml</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">---</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">title</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">AI-Augmented Development Pipelines</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">budget</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">£200/month</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">constraints</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: [</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">client delivery</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">GDPR</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">, </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">legacy WP + Laravel</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">]</span></span>
<span class="line"><span style="--shiki-light:#22863A;--shiki-dark:#85E89D;">target_outcomes</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">:</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  - </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">reduce PR cycle time</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  - </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">improve test coverage</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  - </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">reduce regressions</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">---</span></span></code></pre></div><p><strong>Effort:</strong> Medium (3 hours to standardise format and update runner) <strong>Impact:</strong> Medium-High (makes the workflow reproducible and version-controlled)</p>`,57)])])}const k=e(o,[["render",r]]);export{u as __pageData,k as default};
